sys_inbound_email_action.script:
(function runAction(/*GlideRecord*/ current, /*GlideEmailReader*/ email) {

    // Use the ITSMEmailParser to extract and set incident fields
    var parser = new ITSMEmailParser();
    var success = parser.parseAndCreateIncident(email, current);

    if (success) {
        gs.info('Inbound Email: Incident created from email - Subject: ' + email.subject);

        // Set additional fields specific to email creation
        current.contact_type = 'email';

        // The Business Rule "Set L1 Group Assignment" will auto-assign
        // the appropriate L1 group based on the category that was extracted

        return true;
    } else {
        gs.error('Inbound Email: Failed to create incident from email: ' + email.subject);
        return false;
    }

})(current, email);
